parameters.jsonBody:
={{ JSON.stringify([
  {
    op: 'add',
    path: '/fields/System.Title',
    value: '[' + $json.body.id + '] ' + $json.body.title
  },
  {
    op: 'add',
    path: '/fields/System.Description',
    value: '<b>Bug ID:</b> ' + $json.body.id + '<br><b>Severity:</b> ' + $json.body.severity + '<br><b>Reported by:</b> ' + $json.body.tester + '<br><b>Page:</b> ' + $json.body.page + '<br><b>Device:</b> ' + $json.body.device + '<br><b>Category:</b> ' + ($json.body.category || 'N/A') + '<hr><p>' + $json.body.description + '</p>' + (($json.body.attachments && $json.body.attachments.length) ? '<hr><b>Attachments:</b><br>' + $json.body.attachments.map(a => a.type && a.type.startsWith('image/') ? '<p><b>' + a.name + '</b><br><img src="' + a.url + '" alt="' + a.name + '" style="max-width:600px"></p>' : '<p><a href="' + a.url + '">' + a.name + '</a></p>').join('') : '')
  },
  {
    op: 'add',
    path: '/fields/Microsoft.VSTS.Common.Severity',
    value: ({ critical: '1 - Critical', high: '2 - High', low: '3 - Medium' })[$json.body.severity] || '3 - Medium'
  },
  {
    op: 'add',
    path: '/fields/System.Tags',
    value: 'bug-tracker; ' + $json.body.severity + '; ' + $json.body.tester
  },
  {
    op: 'add',
    path: '/fields/Microsoft.VSTS.TCM.ReproSteps',
    value: '<p>' + $json.body.description + '</p>' + (($json.body.attachments && $json.body.attachments.length) ? '<hr><b>Attachments:</b><br>' + $json.body.attachments.map(a => a.type && a.type.startsWith('image/') ? '<p><b>' + a.name + '</b><br><img src="' + a.url + '" alt="' + a.name + '" style="max-width:600px"></p>' : '<p><a href="' + a.url + '">' + a.name + '</a></p>').join('') : '')
  },
  {
    op: 'add',
    path: '/fields/System.AreaPath',
    value: 'Hospitality Accommodation\\EVO-IBE'
  }
]) }}
